module RefModule(
		input wire [7:0] dato, 
		input wire EN,
		input wire clk,
		input wire rst,
		output reg [7:0] dato_out 
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk, posedge rst or posedge dbg_halt)
	if (rst)
		dato_out <= 8'b0;
	else if (EN)
		dato_out <= dato;

endmodule
